import{_ as t,o as s,c as o,a0 as d}from"./chunks/framework.DTwdCQre.js";const u=JSON.parse('{"title":"Project Baseline","description":"","frontmatter":{},"headers":[],"relativePath":"project-baseline.md","filePath":"project-baseline.md","lastUpdated":1777727293000}'),a={name:"project-baseline.md"};function r(i,e,n,c,l,p){return s(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="project-baseline" tabindex="-1">Project Baseline <a class="header-anchor" href="#project-baseline" aria-label="Permalink to &quot;Project Baseline&quot;">​</a></h1><p>Last checked: 2026-04-28</p><p>This page records the baseline for the <code>world-class-go-agent-rewrite</code> OpenSpec change. It separates real product gaps from sandbox or environment constraints so future fixes can be measured against the same evidence.</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Result</th><th>Notes</th></tr></thead><tbody><tr><td><code>go test -count=1 ./...</code></td><td>Pass</td><td>All Go packages pass outside cache.</td></tr><tr><td><code>make test</code></td><td>Pass with unrestricted local test permissions</td><td>The normal sandbox blocks <code>httptest</code> sockets and user-home log/session writes. With local sockets and writable user cache paths allowed, the wrapper passes.</td></tr><tr><td><code>npm run build</code> in <code>docs/</code></td><td>Pass</td><td>VitePress build succeeds.</td></tr><tr><td><code>python -m pytest harness -v</code> before building <code>bin/go-code</code></td><td>Pass with skips</td><td>CLI scenario tests skip when <code>bin/go-code</code> is missing.</td></tr><tr><td><code>go build -o bin/go-code ./cmd/go-code</code></td><td>Pass</td><td>The sandbox may warn about read-only Go module stat cache; the binary is produced.</td></tr><tr><td><code>python -m pytest harness -v</code> after building <code>bin/go-code</code></td><td>Fail</td><td>29 passed, 5 failed. Failures are CLI scenario assertions with empty stdout.</td></tr><tr><td><code>openspec validate world-class-go-agent-rewrite --strict</code></td><td>Pass</td><td>Change artifacts validate.</td></tr></tbody></table><h2 id="harness-failures" tabindex="-1">Harness Failures <a class="header-anchor" href="#harness-failures" aria-label="Permalink to &quot;Harness Failures&quot;">​</a></h2><p>After building <code>bin/go-code</code>, the Python harness can run the CLI scenarios and exposes these failures:</p><table tabindex="0"><thead><tr><th>Test</th><th>Failure</th></tr></thead><tbody><tr><td><code>harness/test_permission_flow.py::TestPermissionFlow::test_permission_allowed</code></td><td>Expected CLI output, got empty stdout.</td></tr><tr><td><code>harness/test_permission_flow.py::TestPermissionFlow::test_permission_denied</code></td><td>Expected CLI output, got empty stdout.</td></tr><tr><td><code>harness/test_scenarios.py::TestStreamingText::test_streaming_text</code></td><td>Expected streaming text, got empty stdout.</td></tr><tr><td><code>harness/test_scenarios.py::TestToolRoundtrip::test_tool_roundtrip_read</code></td><td>Expected file-read output, got empty stdout.</td></tr><tr><td><code>harness/test_scenarios.py::TestToolRoundtrip::test_tool_roundtrip_bash</code></td><td>Expected bash output, got empty stdout.</td></tr></tbody></table><p>These are product-level gaps, not just test noise: the deterministic CLI harness is not proving prompt mode, streaming, tool roundtrip, or permission behavior yet.</p><h2 id="environment-notes" tabindex="-1">Environment Notes <a class="header-anchor" href="#environment-notes" aria-label="Permalink to &quot;Environment Notes&quot;">​</a></h2><ul><li>Localhost socket tests require permission to bind loopback ports.</li><li>Some Go tests write under the user&#39;s home directory for logs or sessions.</li><li>The docs build writes generated files under <code>docs/.vitepress/dist</code>.</li><li>Harness CLI scenarios depend on a built binary at <code>bin/go-code</code>.</li></ul>',11)])])}const m=t(a,[["render",r]]);export{u as __pageData,m as default};
